code.C:
#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long x = N - 1;
        long long y = N;
        printf("%lld %lld\n", x, y);
    }
    return 0;
}

